INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:73', 55, 73, 27, 534, 4974, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِۚ  ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055073.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:74', 55, 74, 27, 534, 4975, 'لَمْ يَطْمِثْهُنَّ اِنْسٌ قَبْلَهُمْ وَلَا جَاۤنٌّۚ  ', 'Mereka tidak pernah disentuh oleh manusia sebelum mereka dan tidak (pula) oleh jin.', '', 'https://everyayah.com/data/Alafasy_128kbps/055074.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:75', 55, 75, 27, 534, 4976, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِۚ  ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055075.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:76', 55, 76, 27, 534, 4977, 'مُتَّكِـِٕيْنَ عَلٰى رَفْرَفٍ خُضْرٍ وَّعَبْقَرِيٍّ حِسَانٍۚ  ', ' Mereka bertelekan pada bantal-bantal yang hijau dan permadani-permadani yang indah.', '', 'https://everyayah.com/data/Alafasy_128kbps/055076.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:77', 55, 77, 27, 534, 4978, 'فَبِاَيِّ اٰلَاۤءِ رَبِّكُمَا تُكَذِّبٰنِۚ ', ' Maka, nikmat Tuhanmu manakah yang kamu dustakan (wahai jin dan manusia)?', '', 'https://everyayah.com/data/Alafasy_128kbps/055077.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('55:78', 55, 78, 27, 534, 4979, 'تَبٰرَكَ اسْمُ رَبِّكَ ذِى الْجَلٰلِ وَالْاِكْرَامِ ࣖ ', ' Maha Berkah nama Tuhanmu Pemilik keagungan dan kemuliaan.', '', 'https://everyayah.com/data/Alafasy_128kbps/055078.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:1', 56, 1, 27, 534, 4980, 'اِذَا وَقَعَتِ الْوَاقِعَةُۙ ', ' Apabila terjadi hari Kiamat (yang pasti terjadi),', '', 'https://everyayah.com/data/Alafasy_128kbps/056001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:2', 56, 2, 27, 534, 4981, 'لَيْسَ لِوَقْعَتِهَا كَاذِبَةٌ  ۘ ', ' tidak ada seorang pun yang (dapat) mendustakan terjadinya. ', '', 'https://everyayah.com/data/Alafasy_128kbps/056002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:3', 56, 3, 27, 534, 4982, 'خَافِضَةٌ رَّافِعَةٌ ', ' (Kejadian itu) merendahkan (satu golongan) dan meninggikan (golongan yang lain).', '', 'https://everyayah.com/data/Alafasy_128kbps/056003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:4', 56, 4, 27, 534, 4983, 'اِذَا رُجَّتِ الْاَرْضُ رَجًّاۙ ', ' Apabila bumi diguncangkan sedahsyat-dahsyatnya', '', 'https://everyayah.com/data/Alafasy_128kbps/056004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:5', 56, 5, 27, 534, 4984, 'وَّبُسَّتِ الْجِبَالُ بَسًّاۙ  ', ' dan gunung-gunung dihancurkan sehancur-hancurnya,', '', 'https://everyayah.com/data/Alafasy_128kbps/056005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:6', 56, 6, 27, 534, 4985, 'فَكَانَتْ هَبَاۤءً مُّنْۢبَثًّاۙ ', ' jadilah ia debu yang beterbangan.', '', 'https://everyayah.com/data/Alafasy_128kbps/056006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:7', 56, 7, 27, 534, 4986, 'وَّكُنْتُمْ اَزْوَاجًا ثَلٰثَةً ۗ', 'Kamu menjadi tiga golongan,', '', 'https://everyayah.com/data/Alafasy_128kbps/056007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:8', 56, 8, 27, 534, 4987, 'فَاَصْحٰبُ الْمَيْمَنَةِ ەۙ مَآ اَصْحٰبُ الْمَيْمَنَةِ ۗ', 'yaitu golongan kanan, alangkah mulianya golongan kanan itu', '', 'https://everyayah.com/data/Alafasy_128kbps/056008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:9', 56, 9, 27, 534, 4988, 'وَاَصْحٰبُ الْمَشْـَٔمَةِ ەۙ مَآ اَصْحٰبُ الْمَشْـَٔمَةِ ۗ', ' dan golongan kiri, alangkah sengsaranya golongan kiri itu.', '', 'https://everyayah.com/data/Alafasy_128kbps/056009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:10', 56, 10, 27, 534, 4989, 'وَالسّٰبِقُوْنَ السّٰبِقُوْنَۙ  ', 'Selain itu, (golongan ketiga adalah) orang-orang yang paling dahulu (beriman). Merekalah yang paling dahulu (masuk surga).', '', 'https://everyayah.com/data/Alafasy_128kbps/056010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:11', 56, 11, 27, 534, 4990, 'اُولٰۤىِٕكَ الْمُقَرَّبُوْنَۚ ', ' Mereka itulah orang-orang yang didekatkan (kepada Allah).', '', 'https://everyayah.com/data/Alafasy_128kbps/056011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:12', 56, 12, 27, 534, 4991, 'فِيْ جَنّٰتِ النَّعِيْمِ ', ' (Mereka) berada dalam surga (yang penuh) kenikmatan.', '', 'https://everyayah.com/data/Alafasy_128kbps/056012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:13', 56, 13, 27, 534, 4992, 'ثُلَّةٌ مِّنَ الْاَوَّلِيْنَۙ  ', ' (Mereka adalah) segolongan besar dari orang-orang yang terdahulu', '', 'https://everyayah.com/data/Alafasy_128kbps/056013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:14', 56, 14, 27, 534, 4993, 'وَقَلِيْلٌ مِّنَ الْاٰخِرِيْنَۗ  ', ' dan sedikit dari orang-orang yang (datang) kemudian.', '', 'https://everyayah.com/data/Alafasy_128kbps/056014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:15', 56, 15, 27, 534, 4994, 'عَلٰى سُرُرٍ مَّوْضُوْنَةٍۙ  ', ' (Mereka berada) di atas dipan-dipan yang bertatahkan emas dan permata', '', 'https://everyayah.com/data/Alafasy_128kbps/056015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:16', 56, 16, 27, 534, 4995, 'مُّتَّكِـِٕيْنَ عَلَيْهَا مُتَقٰبِلِيْنَ', ' seraya bersandar di atasnya saling berhadapan.', '', 'https://everyayah.com/data/Alafasy_128kbps/056016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:17', 56, 17, 27, 535, 4996, 'يَطُوْفُ عَلَيْهِمْ وِلْدَانٌ مُّخَلَّدُوْنَۙ  ', 'Mereka dikelilingi oleh anak-anak yang selalu muda', '', 'https://everyayah.com/data/Alafasy_128kbps/056017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:18', 56, 18, 27, 535, 4997, 'بِاَكْوَابٍ وَّاَبَارِيْقَۙ وَكَأْسٍ مِّنْ مَّعِيْنٍۙ  ', 'dengan (membawa) gelas, kendi, dan seloki (berisi minuman yang diambil) dari sumber yang mengalir.', '', 'https://everyayah.com/data/Alafasy_128kbps/056018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:19', 56, 19, 27, 535, 4998, 'لَّا يُصَدَّعُوْنَ عَنْهَا وَلَا يُنْزِفُوْنَۙ  ', ' Mereka tidak pening karenanya dan tidak pula mabuk.', '', 'https://everyayah.com/data/Alafasy_128kbps/056019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:20', 56, 20, 27, 535, 4999, 'وَفَاكِهَةٍ مِّمَّا يَتَخَيَّرُوْنَۙ  ', ' (Mereka menyuguhkan pula) buah-buahan yang mereka pilih', '', 'https://everyayah.com/data/Alafasy_128kbps/056020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:21', 56, 21, 27, 535, 5000, 'وَلَحْمِ طَيْرٍ مِّمَّا يَشْتَهُوْنَۗ  ', ' dan daging burung yang mereka sukai.', '', 'https://everyayah.com/data/Alafasy_128kbps/056021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:22', 56, 22, 27, 535, 5001, 'وَحُوْرٌ عِيْنٌۙ  ', 'Ada bidadari yang bermata indah', '', 'https://everyayah.com/data/Alafasy_128kbps/056022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:23', 56, 23, 27, 535, 5002, 'كَاَمْثَالِ اللُّؤْلُؤِ الْمَكْنُوْنِۚ  ', ' laksana mutiara yang tersimpan dengan baik', '', 'https://everyayah.com/data/Alafasy_128kbps/056023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:24', 56, 24, 27, 535, 5003, 'جَزَاۤءًۢ بِمَا كَانُوْا يَعْمَلُوْنَ', ' sebagai balasan atas apa yang selama ini mereka kerjakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/056024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:25', 56, 25, 27, 535, 5004, 'لَا يَسْمَعُوْنَ فِيْهَا لَغْوًا وَّلَا تَأْثِيْمًاۙ  ', 'Di sana mereka tidak mendengar percakapan yang sia-sia dan tidak (pula) percakapan yang menimbulkan dosa,', '', 'https://everyayah.com/data/Alafasy_128kbps/056025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:26', 56, 26, 27, 535, 5005, 'اِلَّا قِيْلًا سَلٰمًا سَلٰمًا ', ' kecuali (yang mereka dengar hanyalah) ucapan, “Salam… salam.”', '', 'https://everyayah.com/data/Alafasy_128kbps/056026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:27', 56, 27, 27, 535, 5006, 'وَاَصْحٰبُ الْيَمِيْنِ ەۙ مَآ اَصْحٰبُ الْيَمِيْنِۗ', ' Golongan kanan, alangkah mulianya golongan kanan itu.', '', 'https://everyayah.com/data/Alafasy_128kbps/056027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:28', 56, 28, 27, 535, 5007, 'فِيْ سِدْرٍ مَّخْضُوْدٍۙ  ', ' (Mereka) berada di antara pohon bidara yang tidak berduri,', '', 'https://everyayah.com/data/Alafasy_128kbps/056028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:29', 56, 29, 27, 535, 5008, 'وَّطَلْحٍ مَّنْضُوْدٍۙ  ', ' pohon pisang yang (buahnya) bersusun-susun, ', '', 'https://everyayah.com/data/Alafasy_128kbps/056029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:30', 56, 30, 27, 535, 5009, 'وَّظِلٍّ مَّمْدُوْدٍۙ  ', ' naungan yang terbentang luas,', '', 'https://everyayah.com/data/Alafasy_128kbps/056030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:31', 56, 31, 27, 535, 5010, 'وَّمَاۤءٍ مَّسْكُوْبٍۙ  ', ' air yang tercurah,', '', 'https://everyayah.com/data/Alafasy_128kbps/056031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:32', 56, 32, 27, 535, 5011, 'وَّفَاكِهَةٍ كَثِيْرَةٍۙ  ', 'buah-buahan yang banyak', '', 'https://everyayah.com/data/Alafasy_128kbps/056032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:33', 56, 33, 27, 535, 5012, 'لَّا مَقْطُوْعَةٍ وَّلَا مَمْنُوْعَةٍۙ  ', ' yang tidak berhenti berbuah dan tidak terlarang memetiknya,', '', 'https://everyayah.com/data/Alafasy_128kbps/056033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:34', 56, 34, 27, 535, 5013, 'وَّفُرُشٍ مَّرْفُوْعَةٍۗ  ', 'dan kasur-kasur yang tebal lagi empuk.', '', 'https://everyayah.com/data/Alafasy_128kbps/056034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:35', 56, 35, 27, 535, 5014, 'اِنَّآ اَنْشَأْنٰهُنَّ اِنْشَاۤءًۙ  ', ' Sesungguhnya Kami menciptakan mereka (bidadari itu) secara langsung,', '', 'https://everyayah.com/data/Alafasy_128kbps/056035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:36', 56, 36, 27, 535, 5015, 'فَجَعَلْنٰهُنَّ اَبْكَارًاۙ  ', 'lalu Kami jadikan mereka perawan-perawan', '', 'https://everyayah.com/data/Alafasy_128kbps/056036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:37', 56, 37, 27, 535, 5016, 'عُرُبًا اَتْرَابًاۙ  ', ' yang penuh cinta (lagi) sebaya umurnya,', '', 'https://everyayah.com/data/Alafasy_128kbps/056037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:38', 56, 38, 27, 535, 5017, 'لِّاَصْحٰبِ الْيَمِيْنِۗ  ', ' (diperuntukkan)bagi golongan kanan,', '', 'https://everyayah.com/data/Alafasy_128kbps/056038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:39', 56, 39, 27, 535, 5018, 'ثُلَّةٌ مِّنَ الْاَوَّلِيْنَۙ  ', ' (yaitu) segolongan besar dari orang-orang yang terdahulu', '', 'https://everyayah.com/data/Alafasy_128kbps/056039.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:40', 56, 40, 27, 535, 5019, 'وَثُلَّةٌ مِّنَ الْاٰخِرِيْنَۗ  ࣖ', ' dan segolongan besar (pula) dari orang-orang yang kemudian.', '', 'https://everyayah.com/data/Alafasy_128kbps/056040.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:41', 56, 41, 27, 535, 5020, 'وَاَصْحٰبُ الشِّمَالِ ەۙ مَآ اَصْحٰبُ الشِّمَالِۗ', ' Golongan kiri, alangkah sengsaranya golongan kiri itu.', '', 'https://everyayah.com/data/Alafasy_128kbps/056041.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:42', 56, 42, 27, 535, 5021, 'فِيْ سَمُوْمٍ وَّحَمِيْمٍۙ  ', '(Mereka berada) dalam siksaan angin yang sangat panas, air yang mendidih,', '', 'https://everyayah.com/data/Alafasy_128kbps/056042.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:43', 56, 43, 27, 535, 5022, 'وَّظِلٍّ مِّنْ يَّحْمُوْمٍۙ  ', ' dan naungan asap hitam', '', 'https://everyayah.com/data/Alafasy_128kbps/056043.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:44', 56, 44, 27, 535, 5023, 'لَّا بَارِدٍ وَّلَا كَرِيْمٍ ', 'yang tidak sejuk dan tidak menyenangkan.', '', 'https://everyayah.com/data/Alafasy_128kbps/056044.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:45', 56, 45, 27, 535, 5024, 'اِنَّهُمْ كَانُوْا قَبْلَ ذٰلِكَ مُتْرَفِيْنَۚ ', ' Sesungguhnya mereka sebelum ituhidup bermewah-mewah.', '', 'https://everyayah.com/data/Alafasy_128kbps/056045.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:46', 56, 46, 27, 535, 5025, 'وَكَانُوْا يُصِرُّوْنَ عَلَى الْحِنْثِ الْعَظِيْمِۚ  ', ' Mereka terus-menerus mengerjakan dosa yang besar.', '', 'https://everyayah.com/data/Alafasy_128kbps/056046.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:47', 56, 47, 27, 535, 5026, 'وَكَانُوْا يَقُوْلُوْنَ ەۙ اَىِٕذَا مِتْنَا وَكُنَّا تُرَابًا وَّعِظَامًا ءَاِنَّا لَمَبْعُوْثُوْنَۙ', 'Mereka berkata, “Apabila kami telahmati menjadi tanah dan tulang-belulang,apakah kami benar-benar akan dibangkitkan (kembali)? ', '', 'https://everyayah.com/data/Alafasy_128kbps/056047.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:48', 56, 48, 27, 535, 5027, 'اَوَاٰبَاۤؤُنَا الْاَوَّلُوْنَ ', ' Apakah nenek moyang kami yang terdahulu (akan dibangkitkan pula)?”', '', 'https://everyayah.com/data/Alafasy_128kbps/056048.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:49', 56, 49, 27, 535, 5028, 'قُلْ اِنَّ الْاَوَّلِيْنَ وَالْاٰخِرِيْنَۙ ', 'Katakanlah (Nabi Muhammad), “Sesungguhnya orang-orang yang terdahulu dan yang kemudian', '', 'https://everyayah.com/data/Alafasy_128kbps/056049.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:50', 56, 50, 27, 535, 5029, 'لَمَجْمُوْعُوْنَۙ اِلٰى مِيْقَاتِ يَوْمٍ مَّعْلُوْمٍ ', 'benar-benar akan dikumpulkan pada waktu tertentu, yaitu hari yang sudah diketahui.', '', 'https://everyayah.com/data/Alafasy_128kbps/056050.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:51', 56, 51, 27, 536, 5030, 'ثُمَّ اِنَّكُمْ اَيُّهَا الضَّاۤ لُّوْنَ الْمُكَذِّبُوْنَۙ  ', ' Kemudian, sesungguhnya kamu, 
wahai orang-orang sesat lagi pendusta,
', '', 'https://everyayah.com/data/Alafasy_128kbps/056051.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:52', 56, 52, 27, 536, 5031, 'لَاٰكِلُوْنَ مِنْ شَجَرٍ مِّنْ زَقُّوْمٍۙ  ', 'pasti akan memakan pohon zaqum.707)', '707)Zaqum adalah jenis pohon di neraka yang mengakibatkan derita yang luar biasa bagi yang memakannya.', 'https://everyayah.com/data/Alafasy_128kbps/056052.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:53', 56, 53, 27, 536, 5032, 'فَمَالِـُٔوْنَ مِنْهَا الْبُطُوْنَۚ  ', ' Lalu, kamu akan memenuhi perut-perutmu dengannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/056053.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:54', 56, 54, 27, 536, 5033, 'فَشٰرِبُوْنَ عَلَيْهِ مِنَ الْحَمِيْمِۚ  ', 'Setelah itu, untuk penawarnya (zaqum) kamu akan meminum air yang sangat panas.', '', 'https://everyayah.com/data/Alafasy_128kbps/056054.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:55', 56, 55, 27, 536, 5034, 'فَشٰرِبُوْنَ شُرْبَ الْهِيْمِۗ  ', 'Maka, kamu minum bagaikan unta yang sangat haus.', '', 'https://everyayah.com/data/Alafasy_128kbps/056055.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:56', 56, 56, 27, 536, 5035, 'هٰذَا نُزُلُهُمْ يَوْمَ الدِّيْنِۗ  ', ' Inilah hidangan (untuk) mereka pada hari Pembalasan.”', '', 'https://everyayah.com/data/Alafasy_128kbps/056056.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:57', 56, 57, 27, 536, 5036, 'نَحْنُ خَلَقْنٰكُمْ فَلَوْلَا تُصَدِّقُوْنَ ', ' Kami telah menciptakanmu.  Mengapa kamu tidak membenarkan (hari Kebangkitan)?', '', 'https://everyayah.com/data/Alafasy_128kbps/056057.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:58', 56, 58, 27, 536, 5037, 'اَفَرَءَيْتُمْ مَّا تُمْنُوْنَۗ  ', 'Apakah kamu memperhatikan apa yang kamu pancarkan (sperma)?', '', 'https://everyayah.com/data/Alafasy_128kbps/056058.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:59', 56, 59, 27, 536, 5038, 'ءَاَنْتُمْ تَخْلُقُوْنَهٗٓ اَمْ نَحْنُ الْخٰلِقُوْنَ ', ' Apakah kamu yang menciptakannya atau Kami Penciptanya?', '', 'https://everyayah.com/data/Alafasy_128kbps/056059.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:60', 56, 60, 27, 536, 5039, 'نَحْنُ قَدَّرْنَا بَيْنَكُمُ الْمَوْتَ وَمَا نَحْنُ بِمَسْبُوْقِيْنَۙ  ', ' Kami telah menentukan kematian di antara kamu dan Kami tidak lemah', '', 'https://everyayah.com/data/Alafasy_128kbps/056060.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:61', 56, 61, 27, 536, 5040, 'عَلٰٓى اَنْ نُّبَدِّلَ اَمْثَالَكُمْ وَنُنْشِئَكُمْ فِيْ مَا لَا تَعْلَمُوْنَ', 'untuk mengubah bentukmu (di hari Kiamat) dan menciptakanmu kelak dalam keadaan yang tidak kamu ketahui.', '', 'https://everyayah.com/data/Alafasy_128kbps/056061.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:62', 56, 62, 27, 536, 5041, 'وَلَقَدْ عَلِمْتُمُ النَّشْاَةَ الْاُوْلٰى فَلَوْلَا تَذَكَّرُوْنَ ', ' Sungguh, kamu benar-benar telah mengetahui penciptaan yang pertama. Mengapa kamu tidak mengambil pelajaran?', '', 'https://everyayah.com/data/Alafasy_128kbps/056062.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:63', 56, 63, 27, 536, 5042, 'اَفَرَءَيْتُمْ مَّا تَحْرُثُوْنَۗ  ', ' Apakah kamu memperhatikan benih yang kamu tanam?', '', 'https://everyayah.com/data/Alafasy_128kbps/056063.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:64', 56, 64, 27, 536, 5043, 'ءَاَنْتُمْ تَزْرَعُوْنَهٗٓ اَمْ نَحْنُ الزّٰرِعُوْنَ ', ' Apakah kamu yang menumbuhkannya atau Kami yang menumbuhkan?', '', 'https://everyayah.com/data/Alafasy_128kbps/056064.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:65', 56, 65, 27, 536, 5044, 'لَوْ نَشَاۤءُ لَجَعَلْنٰهُ حُطَامًا فَظَلْتُمْ تَفَكَّهُوْنَۙ  ', 'Seandainya Kami berkehendak, Kami benar-benar menjadikannya hancur sehingga kamu menjadi heran tercengang,', '', 'https://everyayah.com/data/Alafasy_128kbps/056065.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:66', 56, 66, 27, 536, 5045, 'اِنَّا لَمُغْرَمُوْنَۙ  ', '(sambil berkata,) “Sesungguhnya kami benar-benar menderita kerugian.', '', 'https://everyayah.com/data/Alafasy_128kbps/056066.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:67', 56, 67, 27, 536, 5046, 'بَلْ نَحْنُ مَحْرُوْمُوْنَ ', 'Bahkan, kami tidak mendapat hasil apa pun.”', '', 'https://everyayah.com/data/Alafasy_128kbps/056067.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:68', 56, 68, 27, 536, 5047, 'اَفَرَءَيْتُمُ الْمَاۤءَ الَّذِيْ تَشْرَبُوْنَۗ  ', ' Apakah kamu memperhatikan air yang kamu minum?', '', 'https://everyayah.com/data/Alafasy_128kbps/056068.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:69', 56, 69, 27, 536, 5048, 'ءَاَنْتُمْ اَنْزَلْتُمُوْهُ مِنَ الْمُزْنِ اَمْ نَحْنُ الْمُنْزِلُوْنَ ', ' Apakah kamu yang menurunkannya dari awan atau Kami yang menurunkan?', '', 'https://everyayah.com/data/Alafasy_128kbps/056069.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:70', 56, 70, 27, 536, 5049, 'لَوْ نَشَاۤءُ جَعَلْنٰهُ اُجَاجًا فَلَوْلَا تَشْكُرُوْنَ ', ' Seandainya Kami berkehendak, Kami menjadikannya asin. Mengapa kamu tidak bersyukur?', '', 'https://everyayah.com/data/Alafasy_128kbps/056070.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:71', 56, 71, 27, 536, 5050, 'اَفَرَءَيْتُمُ النَّارَ الَّتِيْ تُوْرُوْنَۗ  ', ' Apakah kamu memperhatikan api yang kamu nyalakan?', '', 'https://everyayah.com/data/Alafasy_128kbps/056071.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:72', 56, 72, 27, 536, 5051, 'ءَاَنْتُمْ اَنْشَأْتُمْ شَجَرَتَهَآ اَمْ نَحْنُ الْمُنْشِـُٔوْنَ ', ' Apakah kamu yang menumbuhkan kayunya atau Kami yang menumbuhkan?', '', 'https://everyayah.com/data/Alafasy_128kbps/056072.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:73', 56, 73, 27, 536, 5052, 'نَحْنُ جَعَلْنٰهَا تَذْكِرَةً وَّمَتَاعًا لِّلْمُقْوِيْنَۚ ', 'Kami menjadikannya (api itu) sebagai peringatan dan manfaat bagi para musafir.', '', 'https://everyayah.com/data/Alafasy_128kbps/056073.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:74', 56, 74, 27, 536, 5053, 'فَسَبِّحْ بِاسْمِ رَبِّكَ الْعَظِيْمِ ࣖ ', 'Maka, bertasbihlah dengan (menyebut) nama Tuhanmu Yang Maha Agung.', '', 'https://everyayah.com/data/Alafasy_128kbps/056074.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:75', 56, 75, 27, 536, 5054, '۞ فَلَآ اُقْسِمُ بِمَوٰقِعِ النُّجُوْمِ ', 'Aku bersumpah demi tempat beredarnya bintang-bintang.', '', 'https://everyayah.com/data/Alafasy_128kbps/056075.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:76', 56, 76, 27, 536, 5055, 'وَاِنَّهٗ لَقَسَمٌ لَّوْ تَعْلَمُوْنَ عَظِيْمٌۙ  ', ' Sesungguhnya itu benar-benar sumpah yang sangat besar seandainya kamu mengetahui.', '', 'https://everyayah.com/data/Alafasy_128kbps/056076.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:77', 56, 77, 27, 537, 5056, 'اِنَّهٗ لَقُرْاٰنٌ كَرِيْمٌۙ  ', ' Sesungguhnya ia  benar-benar Al-Qur’an yang sangat mulia,', '', 'https://everyayah.com/data/Alafasy_128kbps/056077.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:78', 56, 78, 27, 537, 5057, 'فِيْ كِتٰبٍ مَّكْنُوْنٍۙ ', 'dalam Kitab yang terpelihara.', '', 'https://everyayah.com/data/Alafasy_128kbps/056078.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:79', 56, 79, 27, 537, 5058, 'لَّا يَمَسُّهٗٓ اِلَّا الْمُطَهَّرُوْنَۗ  ', 'Tidak ada yang menyentuhnya, kecuali para hamba (Allah) yang disucikan.708)', '708)Hamba Allah yang disucikan, menurut sebagian ulama, adalah orang-orang yang suci dari hadas besar dan kecil. Adapun menurut sebagian lainnya, maksudnya adalah makhluk Allah yang suci dari dosa dan kesalahan, yakni para malaikat.', 'https://everyayah.com/data/Alafasy_128kbps/056079.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:80', 56, 80, 27, 537, 5059, 'تَنْزِيْلٌ مِّنْ رَّبِّ الْعٰلَمِيْنَ ', '(Al-Qur’an) diturunkan dari Tuhan seluruh alam.', '', 'https://everyayah.com/data/Alafasy_128kbps/056080.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:81', 56, 81, 27, 537, 5060, 'اَفَبِهٰذَا الْحَدِيْثِ اَنْتُمْ مُّدْهِنُوْنَۙ ', 'Apakah kamu menganggap remeh berita ini (Al-Qur’an)', '', 'https://everyayah.com/data/Alafasy_128kbps/056081.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:82', 56, 82, 27, 537, 5061, 'وَتَجْعَلُوْنَ رِزْقَكُمْ اَنَّكُمْ تُكَذِّبُوْنَ ', 'dan kamu menjadikan rezeki yang kamu terima (dari Allah) justru untuk mendustakan (Al-Qur’an)?', '', 'https://everyayah.com/data/Alafasy_128kbps/056082.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:83', 56, 83, 27, 537, 5062, 'فَلَوْلَآ اِذَا بَلَغَتِ الْحُلْقُوْمَۙ  ', ' Kalau begitu, mengapa (kamu) tidak (menahan nyawa) ketika telah sampai di kerongkongan,', '', 'https://everyayah.com/data/Alafasy_128kbps/056083.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:84', 56, 84, 27, 537, 5063, 'وَاَنْتُمْ حِيْنَىِٕذٍ تَنْظُرُوْنَۙ  ', ' padahal kamu ketika itu melihat (orang yang sedang sekarat)?', '', 'https://everyayah.com/data/Alafasy_128kbps/056084.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:85', 56, 85, 27, 537, 5064, 'وَنَحْنُ اَقْرَبُ اِلَيْهِ مِنْكُمْ وَلٰكِنْ لَّا تُبْصِرُوْنَ ', 'Kami lebih dekat kepadanya (orang yang sedang sekarat) daripada kamu, tetapi kamu tidak melihat.', '', 'https://everyayah.com/data/Alafasy_128kbps/056085.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:86', 56, 86, 27, 537, 5065, 'فَلَوْلَآ اِنْ كُنْتُمْ غَيْرَ مَدِيْنِيْنَۙ  ', 'Maka, mengapa jika kamu tidak diberi balasan, ', '', 'https://everyayah.com/data/Alafasy_128kbps/056086.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:87', 56, 87, 27, 537, 5066, 'تَرْجِعُوْنَهَآ اِنْ كُنْتُمْ صٰدِقِيْنَ', 'kamu tidak mengembalikannya (nyawa itu) jika kamu orang-orang yang benar?', '', 'https://everyayah.com/data/Alafasy_128kbps/056087.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:88', 56, 88, 27, 537, 5067, 'فَاَمَّآ اِنْ كَانَ مِنَ الْمُقَرَّبِيْنَۙ  ', 'Jika dia (orang yang mati) itu termasuk yang didekatkan (kepada Allah),', '', 'https://everyayah.com/data/Alafasy_128kbps/056088.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:89', 56, 89, 27, 537, 5068, 'فَرَوْحٌ وَّرَيْحَانٌ ەۙ وَّجَنَّتُ نَعِيْمٍ', ' dia memperoleh ketenteraman, rezeki, dan surga (yang penuh) kenikmatan.', '', 'https://everyayah.com/data/Alafasy_128kbps/056089.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:90', 56, 90, 27, 537, 5069, 'وَاَمَّآ اِنْ كَانَ مِنْ اَصْحٰبِ الْيَمِيْنِۙ  ', ' Jika dia (termasuk) golongan kanan,', '', 'https://everyayah.com/data/Alafasy_128kbps/056090.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:91', 56, 91, 27, 537, 5070, 'فَسَلٰمٌ لَّكَ مِنْ اَصْحٰبِ الْيَمِيْنِۗ  ', ' “Salam bagimu” dari (sahabatmu,) golongan kanan.', '', 'https://everyayah.com/data/Alafasy_128kbps/056091.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:92', 56, 92, 27, 537, 5071, 'وَاَمَّآ اِنْ كَانَ مِنَ الْمُكَذِّبِيْنَ الضَّاۤلِّيْنَۙ  ', ' Jika dia termasuk golongan para pendusta lagi sesat,', '', 'https://everyayah.com/data/Alafasy_128kbps/056092.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:93', 56, 93, 27, 537, 5072, 'فَنُزُلٌ مِّنْ حَمِيْمٍۙ  ', ' jamuannya berupa air mendidih', '', 'https://everyayah.com/data/Alafasy_128kbps/056093.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:94', 56, 94, 27, 537, 5073, 'وَّتَصْلِيَةُ جَحِيْمٍ ', ' dan dibakar oleh (neraka) Jahim.', '', 'https://everyayah.com/data/Alafasy_128kbps/056094.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:95', 56, 95, 27, 537, 5074, 'اِنَّ هٰذَا لَهُوَ حَقُّ الْيَقِيْنِۚ  ', ' Sesungguhnya ini benar-benar merupakan hakulyakin.', '', 'https://everyayah.com/data/Alafasy_128kbps/056095.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('56:96', 56, 96, 27, 537, 5075, 'فَسَبِّحْ بِاسْمِ رَبِّكَ الْعَظِيْمِ ࣖ ', ' Maka, bertasbihlah dengan (menyebut) nama Tuhanmu Yang Maha Agung.', '', 'https://everyayah.com/data/Alafasy_128kbps/056096.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:1', 57, 1, 27, 537, 5076, 'سَبَّحَ لِلّٰهِ مَا فِى السَّمٰوٰتِ وَالْاَرْضِۚ وَهُوَ الْعَزِيْزُ الْحَكِيْمُ ', ' Apa yang ada di langit dan di bumi bertasbih kepada Allah. Dialah Yang Maha Perkasa lagi Maha Bijaksana.', '', 'https://everyayah.com/data/Alafasy_128kbps/057001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:2', 57, 2, 27, 537, 5077, 'لَهٗ مُلْكُ السَّمٰوٰتِ وَالْاَرْضِۚ يُحْيٖ وَيُمِيْتُۚ وَهُوَ عَلٰى كُلِّ شَيْءٍ قَدِيْرٌ ', 'Milik-Nyalah kerajaan langit dan bumi. Dia menghidupkan dan mematikan. Dia Maha Kuasa atas segala sesuatu.', '', 'https://everyayah.com/data/Alafasy_128kbps/057002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:3', 57, 3, 27, 537, 5078, 'هُوَ الْاَوَّلُ وَالْاٰخِرُ وَالظَّاهِرُ وَالْبَاطِنُۚ وَهُوَ بِكُلِّ شَيْءٍ عَلِيْمٌ ', 'Dialah Yang Maha Awal, Maha Akhir, Maha Zahir, dan Maha Batin.709) Dia Maha Mengetahui segala sesuatu.', '709)Maha Awal berarti telah ada sebelum segala sesuatu ada sehingga tidak ada yang mendahului-Nya; Maha Akhir berarti akan hidup selamanya setelah segala sesuatu musnah; Maha Zahir berarti wujud-Nya begitu nyata, baik melalui perenungan atas alam semesta yang Dia ciptakan maupunmelalui pembuktian logika dan rasa; dan Maha Batin berarti bahwa zat dan hakikat-Nya tidak bisa dijangkau, baik dengan mata, akal, maupun khayal.', 'https://everyayah.com/data/Alafasy_128kbps/057003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:4', 57, 4, 27, 538, 5079, 'هُوَ الَّذِيْ خَلَقَ السَّمٰوٰتِ وَالْاَرْضَ فِيْ سِتَّةِ اَيَّامٍ ثُمَّ اسْتَوٰى عَلَى الْعَرْشِۗ يَعْلَمُ مَا يَلِجُ فِى الْاَرْضِ وَمَا يَخْرُجُ مِنْهَا وَمَا يَنْزِلُ مِنَ السَّمَاۤءِ وَمَا يَعْرُجُ فِيْهَاۗ وَهُوَ مَعَكُمْ اَيْنَ مَا كُنْتُمْۗ وَاللّٰهُ بِمَا تَعْمَلُوْنَ بَصِيْرٌۗ', ' Dialah yang menciptakan langit dan bumi dalam enam masa. Kemudian, Dia bersemayam di atas ʻArasy. Dia mengetahui apa yang masuk ke dalam bumi dan apa yang keluar darinya serta apa yang turun dari langit dan apa yang naik ke sana.710) Dia bersamamu di mana saja kamu berada. Allah Maha Melihat apa yang kamu kerjakan.', '710)Yang dimaksud dengan yang naik, antara lain, adalah amal-amal dan doa-doa hamba-Nya.', 'https://everyayah.com/data/Alafasy_128kbps/057004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:5', 57, 5, 27, 538, 5080, 'لَهٗ مُلْكُ السَّمٰوٰتِ وَالْاَرْضِۗ وَاِلَى اللّٰهِ تُرْجَعُ الْاُمُوْرُ ', ' Milik-Nyalah kerajaan langit dan bumi. Hanya kepada Allah segala urusan dikembalikan', '', 'https://everyayah.com/data/Alafasy_128kbps/057005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:6', 57, 6, 27, 538, 5081, 'يُوْلِجُ الَّيْلَ فِى النَّهَارِ وَيُوْلِجُ النَّهَارَ فِى الَّيْلِۗ وَهُوَ عَلِيْمٌ ۢبِذَاتِ الصُّدُوْرِ ', ' Dia memasukkan malam ke dalam siang dan memasukkan siang ke dalam malam. Dia Maha Mengetahui segala isi hati.', '', 'https://everyayah.com/data/Alafasy_128kbps/057006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:7', 57, 7, 27, 538, 5082, 'اٰمِنُوْا بِاللّٰهِ وَرَسُوْلِهٖ وَاَنْفِقُوْا مِمَّا جَعَلَكُمْ مُّسْتَخْلَفِيْنَ فِيْهِۗ فَالَّذِيْنَ اٰمَنُوْا مِنْكُمْ وَاَنْفَقُوْا لَهُمْ اَجْرٌ كَبِيْرٌۚ', ' Berimanlah kepada Allah dan Rasul-Nya serta infakkanlah (di jalan Allah) sebagian dari apa yang Dia (titipkan kepadamu dan) telah menjadikanmu berwenang dalam (penggunaan)-nya. Lalu, orang-orang yang beriman di antaramu dan menginfakkan (hartanya di jalan Allah) memperoleh pahala yang sangat besar.', '', 'https://everyayah.com/data/Alafasy_128kbps/057007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:8', 57, 8, 27, 538, 5083, 'وَمَا لَكُمْ لَا تُؤْمِنُوْنَ بِاللّٰهِ ۚوَالرَّسُوْلُ يَدْعُوْكُمْ لِتُؤْمِنُوْا بِرَبِّكُمْ وَقَدْ اَخَذَ مِيْثَاقَكُمْ اِنْ كُنْتُمْ مُّؤْمِنِيْنَ ', ' Mengapa kamu tidak beriman kepada Allah, padahal Rasul mengajakmu beriman kepada Tuhanmu? Sungguh, Dia telah mengambil janji (setia)-mu jika kamu adalah orang-orang mukmin.', '', 'https://everyayah.com/data/Alafasy_128kbps/057008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:9', 57, 9, 27, 538, 5084, 'هُوَ الَّذِيْ يُنَزِّلُ عَلٰى عَبْدِهٖٓ اٰيٰتٍۢ بَيِّنٰتٍ لِّيُخْرِجَكُمْ مِّنَ الظُّلُمٰتِ اِلَى النُّوْرِۗ وَاِنَّ اللّٰهَ بِكُمْ لَرَءُوْفٌ رَّحِيْمٌ ', 'Dialah yang menurunkan ayat-ayat yang terang (Al-Qur’an) kepada hamba-Nya (Nabi Muhammad) untuk mengeluarkanmu dari kegelapan kepada cahaya. Sesungguhnya Allah benar-benar Maha Penyantun lagi Maha Penyayang kepadamu.', '', 'https://everyayah.com/data/Alafasy_128kbps/057009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:10', 57, 10, 27, 538, 5085, 'وَمَا لَكُمْ اَلَّا تُنْفِقُوْا فِيْ سَبِيْلِ اللّٰهِ وَلِلّٰهِ مِيْرَاثُ السَّمٰوٰتِ وَالْاَرْضِۗ  لَا يَسْتَوِيْ مِنْكُمْ مَّنْ اَنْفَقَ مِنْ قَبْلِ الْفَتْحِ وَقَاتَلَۗ  اُولٰۤىِٕكَ اَعْظَمُ دَرَجَةً مِّنَ الَّذِيْنَ اَنْفَقُوْا مِنْۢ بَعْدُ وَقَاتَلُوْاۗ وَكُلًّا وَّعَدَ اللّٰهُ الْحُسْنٰىۗ وَاللّٰهُ بِمَا تَعْمَلُوْنَ خَبِيْرٌ ࣖ ', ' Mengapa kamu tidak menginfakkan (hartamu) di jalan Allah, padahal milik Allah semua pusaka langit dan bumi? Tidak sama orang yang menginfakkan (hartanya di jalan Allah) di antara kamu dan berperang sebelum penaklukan (Makkah). Mereka lebih tinggi derajatnya daripada orang-orang yang menginfakkan (hartanya) dan berperang setelah itu. Allah menjanjikan (balasan) yang baik kepada mereka masing-masing. Allah Maha Teliti terhadap apa yang kamu kerjakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/057010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:11', 57, 11, 27, 538, 5086, 'مَنْ ذَا الَّذِيْ يُقْرِضُ اللّٰهَ قَرْضًا حَسَنًا فَيُضٰعِفَهٗ لَهٗ وَلَهٗٓ اَجْرٌ كَرِيْمٌ ', ' Siapakah yang (mau) memberi pinjaman kepada Allah dengan pinjaman yang baik? Dia akan melipatgandakan (pahala) untuknya, dan baginya (diberikan) ganjaran yang sangat mulia (surga).', '', 'https://everyayah.com/data/Alafasy_128kbps/057011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:12', 57, 12, 27, 539, 5087, 'يَوْمَ تَرَى الْمُؤْمِنِيْنَ وَالْمُؤْمِنٰتِ يَسْعٰى نُوْرُهُمْ بَيْنَ اَيْدِيْهِمْ وَبِاَيْمَانِهِمْ بُشْرٰىكُمُ الْيَوْمَ جَنّٰتٌ تَجْرِيْ مِنْ تَحْتِهَا الْاَنْهٰرُ خٰلِدِيْنَ فِيْهَاۗ ذٰلِكَ هُوَ الْفَوْزُ الْعَظِيْمُۚ ', 'Pada hari engkau akan melihat orang-orang mukmin laki-laki dan perempuan, cahaya mereka memancar di hadapan dan di sebelah kanan mereka. (Dikatakan kepada mereka,) “Pada hari ini ada berita gembira untukmu, (yaitu) surga yang mengalir di bawahnya sungai-sungai (dan) mereka kekal di dalamnya. Demikian itulah kemenangan yang sangat agung.”', '', 'https://everyayah.com/data/Alafasy_128kbps/057012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:13', 57, 13, 27, 539, 5088, 'يَوْمَ يَقُوْلُ الْمُنٰفِقُوْنَ وَالْمُنٰفِقٰتُ لِلَّذِيْنَ اٰمَنُوا انْظُرُوْنَا نَقْتَبِسْ مِنْ نُّوْرِكُمْۚ قِيْلَ ارْجِعُوْا وَرَاۤءَكُمْ فَالْتَمِسُوْا نُوْرًاۗ فَضُرِبَ بَيْنَهُمْ بِسُوْرٍ لَّهٗ بَابٌۗ بَاطِنُهٗ فِيْهِ الرَّحْمَةُ وَظَاهِرُهٗ مِنْ قِبَلِهِ الْعَذَابُۗ', ' Pada hari (itu juga) orang-orang munafik laki-laki dan perempuan berkata kepada orang-orang yang beriman, “Tunggulah kami! Kami ingin mengambil cahayamu.” (Kepada mereka) dikatakan, “Kembalilah kamu ke belakang dan carilah sendiri cahaya (untukmu).” Lalu, di antara mereka dipasang dinding (pemisah) yang berpintu. Di sebelah dalamnya ada rahmat dan di luarnya ada azab.', '', 'https://everyayah.com/data/Alafasy_128kbps/057013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:14', 57, 14, 27, 539, 5089, 'يُنَادُوْنَهُمْ اَلَمْ نَكُنْ مَّعَكُمْۗ قَالُوْا بَلٰى وَلٰكِنَّكُمْ فَتَنْتُمْ اَنْفُسَكُمْ وَتَرَبَّصْتُمْ وَارْتَبْتُمْ وَغَرَّتْكُمُ الْاَمَانِيُّ حَتّٰى جَاۤءَ اَمْرُ اللّٰهِ وَغَرَّكُمْ بِاللّٰهِ الْغَرُوْرُ ', ' Orang-orang (munafik) memanggil mereka (orang-orang beriman), “Bukankah kami dahulu bersama kamu?” Mereka menjawab, “Benar, tetapi kamu mencelakakan dirimu sendiri (dengan kemunafikan), menunggu-nunggu (kebinasaan kami), meragukan (ajaran Islam), dan ditipu oleh angan-angan kosong sampai datang ketetapan Allah. (Setan) penipu memperdayakanmu (sehingga kamu lalai) terhadap Allah.', '', 'https://everyayah.com/data/Alafasy_128kbps/057014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:15', 57, 15, 27, 539, 5090, 'فَالْيَوْمَ لَا يُؤْخَذُ مِنْكُمْ فِدْيَةٌ وَّلَا مِنَ الَّذِيْنَ كَفَرُوْاۗ مَأْوٰىكُمُ النَّارُۗ هِيَ مَوْلٰىكُمْۗ وَبِئْسَ الْمَصِيْرُ ', 'Pada hari ini tidak akan diterima tebusan darimu maupun dari orang-orang yang kufur. Tempatmu adalah neraka. Ia adalah tempat berlindungmu dan seburuk-buruk tempat kembali.”', '', 'https://everyayah.com/data/Alafasy_128kbps/057015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:16', 57, 16, 27, 539, 5091, '۞ اَلَمْ يَأْنِ لِلَّذِيْنَ اٰمَنُوْٓا اَنْ تَخْشَعَ قُلُوْبُهُمْ لِذِكْرِ اللّٰهِ وَمَا نَزَلَ مِنَ الْحَقِّۙ وَلَا يَكُوْنُوْا كَالَّذِيْنَ اُوْتُوا الْكِتٰبَ مِنْ قَبْلُ فَطَالَ عَلَيْهِمُ الْاَمَدُ فَقَسَتْ قُلُوْبُهُمْۗ وَكَثِيْرٌ مِّنْهُمْ فٰسِقُوْنَ  ', ' Apakah belum tiba waktunya bagi orang-orang yang beriman agar hati mereka khusyuk mengingat Allah dan apa yang turun dari kebenaran (Al-Qur’an). Janganlah mereka (berlaku) seperti orang-orang yang telah menerima kitab sebelum itu, kemudian mereka melalui masa yang panjang sehingga hati mereka menjadi keras. Banyak di antara mereka adalah orang-orang fasik.', '', 'https://everyayah.com/data/Alafasy_128kbps/057016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:17', 57, 17, 27, 539, 5092, 'اِعْلَمُوْٓا اَنَّ اللّٰهَ يُحْيِ الْاَرْضَ بَعْدَ مَوْتِهَاۗ قَدْ بَيَّنَّا لَكُمُ الْاٰيٰتِ لَعَلَّكُمْ تَعْقِلُوْنَ ', 'Ketahuilah bahwa Allah menghidupkan bumi setelah matinya (kering). Sungguh, telah Kami jelaskan kepadamu tanda-tanda (kebesaran Kami) agar kamu mengerti.', '', 'https://everyayah.com/data/Alafasy_128kbps/057017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:18', 57, 18, 27, 539, 5093, 'اِنَّ الْمُصَّدِّقِيْنَ وَالْمُصَّدِّقٰتِ وَاَقْرَضُوا اللّٰهَ قَرْضًا حَسَنًا يُّضٰعَفُ لَهُمْ وَلَهُمْ اَجْرٌ كَرِيْمٌ ', 'Sesungguhnya orang-orang yang bersedekah, baik laki-laki maupun perempuan, dan meminjamkan (kepada) Allah pinjaman yang baik, akan dilipatgandakan (balasannya) kepada mereka dan baginya (diberikan) ganjaran yang sangat mulia (surga). ', '', 'https://everyayah.com/data/Alafasy_128kbps/057018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:19', 57, 19, 27, 540, 5094, 'وَالَّذِيْنَ اٰمَنُوْا بِاللّٰهِ وَرُسُلِهٖٓ اُولٰۤىِٕكَ هُمُ الصِّدِّيْقُوْنَ ۖوَالشُّهَدَاۤءُ عِنْدَ رَبِّهِمْۗ  لَهُمْ اَجْرُهُمْ وَنُوْرُهُمْۗ وَالَّذِيْنَ كَفَرُوْا وَكَذَّبُوْا بِاٰيٰتِنَآ اُولٰۤىِٕكَ اَصْحٰبُ الْجَحِيْمِ ࣖ', ' Orang-orang yang beriman kepada Allah dan rasul-rasul-Nya mereka itulah aṣ-ṣiddīqūn (yang sangat kukuh dalam kebenaran dan pembenarannya) dan syuhadā’ (orang-orang yang disaksikan kebenaran dan kebajikannya) di sisi Tuhan mereka. Mereka mendapatkan pahala dan cahaya (dari Tuhan) mereka. Adapun orang-orang yang kufur dan mendustakan ayat-ayat Kami itulah penghuni (neraka) Jahim. ', '', 'https://everyayah.com/data/Alafasy_128kbps/057019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:20', 57, 20, 27, 540, 5095, 'اِعْلَمُوْٓا اَنَّمَا الْحَيٰوةُ الدُّنْيَا لَعِبٌ وَّلَهْوٌ وَّزِيْنَةٌ وَّتَفَاخُرٌۢ بَيْنَكُمْ وَتَكَاثُرٌ فِى الْاَمْوَالِ وَالْاَوْلَادِۗ  كَمَثَلِ غَيْثٍ اَعْجَبَ الْكُفَّارَ نَبَاتُهٗ ثُمَّ يَهِيْجُ فَتَرٰىهُ مُصْفَرًّا ثُمَّ يَكُوْنُ حُطَامًاۗ وَفِى الْاٰخِرَةِ عَذَابٌ شَدِيْدٌۙ وَّمَغْفِرَةٌ مِّنَ اللّٰهِ وَرِضْوَانٌ  ۗوَمَا الْحَيٰوةُ الدُّنْيَآ اِلَّا مَتَاعُ الْغُرُوْرِ ', ' Ketahuilah bahwa kehidupan dunia itu hanyalah permainan, kelengahan, perhiasan, dan saling bermegah-megahan di antara kamu serta berlomba-lomba dalam banyaknya harta dan anak keturunan. (Perumpamaannya adalah) seperti hujan yang tanamannya mengagumkan para petani, lalu mengering dan kamu lihat menguning, kemudian hancur. Di akhirat ada azab yang keras serta ampunan dari Allah dan keridaan-Nya. Kehidupan dunia (bagi orang-orang yang lengah) hanyalah kesenangan yang memperdaya.', '', 'https://everyayah.com/data/Alafasy_128kbps/057020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:21', 57, 21, 27, 540, 5096, 'سَابِقُوْٓا اِلٰى مَغْفِرَةٍ مِّنْ رَّبِّكُمْ وَجَنَّةٍ عَرْضُهَا كَعَرْضِ السَّمَاۤءِ وَالْاَرْضِۙ اُعِدَّتْ لِلَّذِيْنَ اٰمَنُوْا بِاللّٰهِ وَرُسُلِهٖۗ ذٰلِكَ فَضْلُ اللّٰهِ يُؤْتِيْهِ مَنْ يَّشَاۤءُ ۗوَاللّٰهُ ذُو الْفَضْلِ الْعَظِيْمِ', ' Berlombalah menuju ampunan dari Tuhanmu dan surga yang lebarnya (luasnya) selebar langit dan bumi, yang telah disediakan bagi orang-orang yang beriman kepada Allah dan para rasul-Nya. Itulah karunia Allah yang dianugerahkan kepada siapa yang dikehendaki-Nya. Allah adalah Pemilik karunia yang agung. ', '', 'https://everyayah.com/data/Alafasy_128kbps/057021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:22', 57, 22, 27, 540, 5097, 'مَآ اَصَابَ مِنْ مُّصِيْبَةٍ فِى الْاَرْضِ وَلَا فِيْٓ اَنْفُسِكُمْ اِلَّا فِيْ كِتٰبٍ مِّنْ قَبْلِ اَنْ نَّبْرَاَهَا ۗاِنَّ ذٰلِكَ عَلَى اللّٰهِ يَسِيْرٌۖ  ', 'Tidak ada bencana (apa pun) yang menimpa di bumi dan tidak (juga yang menimpa) dirimu, kecuali telah tertulis dalam Kitab (Lauhulmahfuz) sebelum Kami mewujudkannya. Sesungguhnya hal itu mudah bagi Allah. ', '', 'https://everyayah.com/data/Alafasy_128kbps/057022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:23', 57, 23, 27, 540, 5098, 'لِّكَيْلَا تَأْسَوْا عَلٰى مَا فَاتَكُمْ وَلَا تَفْرَحُوْا بِمَآ اٰتٰىكُمْ ۗوَاللّٰهُ لَا يُحِبُّ كُلَّ مُخْتَالٍ فَخُوْرٍۙ', '(Yang demikian itu kami tetapkan) agar kamu tidak bersedih terhadap apa yang luput dari kamu dan tidak pula terlalu gembira terhadap apa yang diberikan-Nya kepadamu. Allah tidak menyukai setiap orang yang sombong lagi membanggakan diri.', '', 'https://everyayah.com/data/Alafasy_128kbps/057023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:24', 57, 24, 27, 540, 5099, ' ۨالَّذِيْنَ يَبْخَلُوْنَ وَيَأْمُرُوْنَ النَّاسَ بِالْبُخْلِ ۗوَمَنْ يَّتَوَلَّ فَاِنَّ اللّٰهَ هُوَ الْغَنِيُّ الْحَمِيْدُ ', '(Mereka itu adalah) orang-orang yang kikir dan menyuruh orang lain (berbuat) kikir. Siapa yang berpaling (dari perintah Allah), sesungguhnya Allah, Dialah Yang Maha Kaya lagi Maha Terpuji. ', '', 'https://everyayah.com/data/Alafasy_128kbps/057024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:25', 57, 25, 27, 541, 5100, 'لَقَدْ اَرْسَلْنَا رُسُلَنَا بِالْبَيِّنٰتِ وَاَنْزَلْنَا مَعَهُمُ الْكِتٰبَ وَالْمِيْزَانَ لِيَقُوْمَ النَّاسُ بِالْقِسْطِۚ وَاَنْزَلْنَا الْحَدِيْدَ فِيْهِ بَأْسٌ شَدِيْدٌ وَّمَنَافِعُ لِلنَّاسِ وَلِيَعْلَمَ اللّٰهُ مَنْ يَّنْصُرُهٗ وَرُسُلَهٗ بِالْغَيْبِۗ اِنَّ اللّٰهَ قَوِيٌّ عَزِيْزٌ ࣖ ', ' Sungguh, Kami benar-benar telah mengutus rasul-rasul Kami dengan bukti-bukti yang nyata dan Kami menurunkan bersama mereka kitab dan neraca (keadilan) agar manusia dapat berlaku adil. Kami menurunkan besi yang mempunyai kekuatan hebat dan berbagai manfaat bagi manusia agar Allah mengetahui siapa yang menolong (agama)-Nya dan rasul-rasul-Nya walaupun (Allah) tidak dilihatnya. Sesungguhnya Allah Maha Kuat lagi Maha Perkasa.', '', 'https://everyayah.com/data/Alafasy_128kbps/057025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:26', 57, 26, 27, 541, 5101, 'وَلَقَدْ اَرْسَلْنَا نُوْحًا وَّاِبْرٰهِيْمَ وَجَعَلْنَا فِيْ ذُرِّيَّتِهِمَا النُّبُوَّةَ وَالْكِتٰبَ فَمِنْهُمْ مُّهْتَدٍۚ وَكَثِيْرٌ مِّنْهُمْ فٰسِقُوْنَ', 'Sungguh, Kami benar-benar telah mengutus Nuh dan Ibrahim serta Kami memberikan kenabian dan kitab (wahyu) kepada keturunan keduanya. Di antara mereka ada yang menerima petunjuk dan banyak pula di antara mereka yang fasik.', '', 'https://everyayah.com/data/Alafasy_128kbps/057026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:27', 57, 27, 27, 541, 5102, 'ثُمَّ قَفَّيْنَا عَلٰٓى اٰثَارِهِمْ بِرُسُلِنَا وَقَفَّيْنَا بِعِيْسَى ابْنِ مَرْيَمَ وَاٰتَيْنٰهُ الْاِنْجِيْلَ ەۙ وَجَعَلْنَا فِيْ قُلُوْبِ الَّذِيْنَ اتَّبَعُوْهُ رَأْفَةً وَّرَحْمَةً  ۗوَرَهْبَانِيَّةَ ِۨابْتَدَعُوْهَا مَا كَتَبْنٰهَا عَلَيْهِمْ اِلَّا ابْتِغَاۤءَ رِضْوَانِ اللّٰهِ فَمَا رَعَوْهَا حَقَّ رِعَايَتِهَا ۚفَاٰتَيْنَا الَّذِيْنَ اٰمَنُوْا مِنْهُمْ اَجْرَهُمْ ۚ وَكَثِيْرٌ مِّنْهُمْ فٰسِقُوْنَ', ' Kemudian, Kami meneruskan jejak mereka dengan (mengutus) rasul-rasul Kami dan Kami meneruskan (pula dengan mengutus) Isa putra Maryam serta Kami memberikan Injil kepadanya. Kami menjadikan kesantunan dan kasih sayang dalam hati orang-orang yang mengikutinya. Mereka mengada-adakan rahbaniah (berlebih-lebihan dalam beribadah). Padahal, Kami tidak mewajibkannya kepada mereka. Akan tetapi, (mereka mengada-adakannya dengan tujuan) mencari keridaan Allah, lalu mereka tidak memeliharanya dengan sebaik-baiknya. Maka, kepada orang-orang yang beriman di antara mereka Kami berikan pahalanya dan di antara mereka banyak yang fasik.', '', 'https://everyayah.com/data/Alafasy_128kbps/057027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:28', 57, 28, 27, 541, 5103, 'يٰٓاَيُّهَا الَّذِيْنَ اٰمَنُوا اتَّقُوا اللّٰهَ وَاٰمِنُوْا بِرَسُوْلِهٖ يُؤْتِكُمْ كِفْلَيْنِ مِنْ رَّحْمَتِهٖ وَيَجْعَلْ لَّكُمْ نُوْرًا تَمْشُوْنَ بِهٖ وَيَغْفِرْ لَكُمْۗ وَاللّٰهُ غَفُوْرٌ رَّحِيْمٌۙ', 'Wahai orang-orang yang beriman, bertakwalah kepada Allah dan berimanlah kepada Rasul-Nya (Nabi Muhammad), niscaya Allah menganugerahkan kepadamu dua bagian dari rahmat-Nya dan menjadikan cahaya untukmu yang dengan cahaya itu kamu berjalan serta Dia mengampunimu. Allah Maha Pengampun lagi Maha Penyayang.', '', 'https://everyayah.com/data/Alafasy_128kbps/057028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('57:29', 57, 29, 27, 541, 5104, 'لِّئَلَّا يَعْلَمَ اَهْلُ الْكِتٰبِ اَلَّا يَقْدِرُوْنَ عَلٰى شَيْءٍ مِّنْ فَضْلِ اللّٰهِ وَاَنَّ الْفَضْلَ بِيَدِ اللّٰهِ يُؤْتِيْهِ مَنْ يَّشَاۤءُ ۗوَاللّٰهُ ذُو الْفَضْلِ الْعَظِيْمِ ࣖ   ۔', ' (Allah menganugerahkan itu) agar Ahlulkitab (yang tidak beriman kepada Nabi Muhammad) mengetahui bahwa mereka sedikit pun tidak akan mendapat karunia Allah dan bahwa karunia itu ada di tangan Allah. Dia menganugerahkannya kepada siapa yang dikehendaki-Nya. Allah Pemilik karunia yang agung.', '', 'https://everyayah.com/data/Alafasy_128kbps/057029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('58:1', 58, 1, 28, 542, 5105, 'قَدْ سَمِعَ اللّٰهُ قَوْلَ الَّتِيْ تُجَادِلُكَ فِيْ زَوْجِهَا وَتَشْتَكِيْٓ اِلَى اللّٰهِ  ۖوَاللّٰهُ يَسْمَعُ تَحَاوُرَكُمَاۗ اِنَّ اللّٰهَ سَمِيْعٌۢ بَصِيْرٌ ', 'Sungguh, Allah telah mendengar ucapan wanita yang mengajukan gugatan kepadamu (Nabi Muhammad) tentang suaminya dan mengadukan kepada Allah, padahal Allah mendengar percakapan kamu berdua. Sesungguhnya Allah Maha Mendengar lagi Maha Melihat.711)', '711) Ayat ini turun berkenaan dengan Khaulah binti Sa‘labah yang dizihar oleh suaminya, Aus bin Samit, dengan mengatakan, “Kamu bagiku seperti punggung ibuku,” dengan maksud tidak akan lagi menggauli istrinya sebagaimana ia tidak akan menggauli ibunya. Dalam adat Jahiliah, kalimat zihar seperti itu sama dengan menalak istri. Khaulah mengadukan hal itu kepada Rasulullah saw. Rasulullah menjawab bahwa Allah belum menurunkan ketentuan hukum tentang zihar. Dalam riwayat lain beliau bersabda, “Engkau telah diharamkan bergaul dengan dia.” Khaulah lalu berkata, “Suamiku belum menyebut kata-kata talak.” Ia berulang kali mendesak Rasulullah agar menetapkan keputusan. Maka, turunlah ayat ini dan ayat-ayat berikutnya.', 'https://everyayah.com/data/Alafasy_128kbps/058001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('58:2', 58, 2, 28, 542, 5106, 'اَلَّذِيْنَ يُظٰهِرُوْنَ مِنْكُمْ مِّنْ نِّسَاۤىِٕهِمْ مَّا هُنَّ اُمَّهٰتِهِمْۗ اِنْ اُمَّهٰتُهُمْ اِلَّا الّٰۤـِٔيْ وَلَدْنَهُمْۗ وَاِنَّهُمْ لَيَقُوْلُوْنَ مُنْكَرًا مِّنَ الْقَوْلِ وَزُوْرًاۗ وَاِنَّ اللّٰهَ لَعَفُوٌّ غَفُوْرٌ ', 'Orang-orang yang menzihar istrinya (menganggapnya sebagai ibu) di antara kamu, istri mereka itu bukanlah ibunya. Ibu-ibu mereka tidak lain hanyalah perempuan yang melahirkannya. Sesungguhnya mereka benar-benar telah mengucapkan suatu perkataan yang mungkar dan dusta. Sesungguhnya Allah benar-benar Maha Pemaaf lagi Maha Pengampun. ', '', 'https://everyayah.com/data/Alafasy_128kbps/058002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('58:3', 58, 3, 28, 542, 5107, 'وَالَّذِيْنَ يُظٰهِرُوْنَ مِنْ نِّسَاۤىِٕهِمْ ثُمَّ يَعُوْدُوْنَ لِمَا قَالُوْا فَتَحْرِيْرُ رَقَبَةٍ مِّنْ قَبْلِ اَنْ يَّتَمَاۤسَّاۗ ذٰلِكُمْ تُوْعَظُوْنَ بِهٖۗ وَاللّٰهُ بِمَا تَعْمَلُوْنَ خَبِيْرٌ ', 'Orang-orang yang menzihar istrinya kemudian menarik kembali apa yang telah mereka ucapkan wajibmemerdekakan seorang budak sebelum kedua suami istri itu berhubungan badan. Demikianlah yang diajarkan kepadamu. Allah Maha Teliti terhadap apa yang kamu kerjakan. ', '', 'https://everyayah.com/data/Alafasy_128kbps/058003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('58:4', 58, 4, 28, 542, 5108, 'فَمَنْ لَّمْ يَجِدْ فَصِيَامُ شَهْرَيْنِ مُتَتَابِعَيْنِ مِنْ قَبْلِ اَنْ يَّتَمَاۤسَّاۗ فَمَنْ لَّمْ يَسْتَطِعْ فَاِطْعَامُ سِتِّيْنَ مِسْكِيْنًاۗ ذٰلِكَ لِتُؤْمِنُوْا بِاللّٰهِ وَرَسُوْلِهٖۗ وَتِلْكَ حُدُوْدُ اللّٰهِ ۗوَلِلْكٰفِرِيْنَ عَذَابٌ اَلِيْمٌ ', 'Siapa yang tidak mendapatkan (hamba sahaya) wajib berpuasa dua bulan berturut-turut sebelum keduanya berhubungan badan. Akan tetapi, siapa yang tidak mampu, (wajib) memberi makan enam puluh orang miskin. Demikianlah agar kamu beriman kepada Allah dan Rasul-Nya. Itulah ketentuan-ketentuan Allah. Orang-orang kafir mendapat azab yang pedih. ', '', 'https://everyayah.com/data/Alafasy_128kbps/058004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('58:5', 58, 5, 28, 542, 5109, 'اِنَّ الَّذِيْنَ يُحَاۤدُّوْنَ اللّٰهَ وَرَسُوْلَهٗ كُبِتُوْا كَمَا كُبِتَ الَّذِيْنَ مِنْ قَبْلِهِمْ وَقَدْ اَنْزَلْنَآ اٰيٰتٍۢ بَيِّنٰتٍۗ وَلِلْكٰفِرِيْنَ عَذَابٌ مُّهِيْنٌۚ ', 'Sesungguhnya orang-orang yang menentang Allah dan Rasul-Nya dihinakan sebagaimana dihinakan orang-orang sebelum mereka. Sungguh, Kami telah menurunkan bukti-bukti yang nyata. Orang-orang kafir mendapat azab yang menghinakan. ', '', 'https://everyayah.com/data/Alafasy_128kbps/058005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('58:6', 58, 6, 28, 542, 5110, 'يَوْمَ يَبْعَثُهُمُ اللّٰهُ جَمِيْعًا فَيُنَبِّئُهُمْ بِمَا عَمِلُوْاۗ  اَحْصٰىهُ اللّٰهُ وَنَسُوْهُۗ وَاللّٰهُ عَلٰى كُلِّ شَيْءٍ شَهِيْدٌ ࣖ', 'Pada hari itu Allah membangkitkan mereka semua, lalu Dia memberitakan kepada mereka apa yang telah mereka kerjakan. Allah menghitungnya (semua amal) meskipun mereka telah melupakannya. Allah Maha Menyaksikan segala sesuatu. ', '', 'https://everyayah.com/data/Alafasy_128kbps/058006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('58:7', 58, 7, 28, 543, 5111, 'اَلَمْ تَرَ اَنَّ اللّٰهَ يَعْلَمُ مَا فِى السَّمٰوٰتِ وَمَا فِى الْاَرْضِۗ مَا يَكُوْنُ مِنْ نَّجْوٰى ثَلٰثَةٍ اِلَّا هُوَ رَابِعُهُمْ وَلَا خَمْسَةٍ اِلَّا هُوَ سَادِسُهُمْ وَلَآ اَدْنٰى مِنْ ذٰلِكَ وَلَآ اَكْثَرَ اِلَّا هُوَ مَعَهُمْ اَيْنَ مَا كَانُوْاۚ  ثُمَّ يُنَبِّئُهُمْ بِمَا عَمِلُوْا يَوْمَ الْقِيٰمَةِۗ اِنَّ اللّٰهَ بِكُلِّ شَيْءٍ عَلِيْمٌ ', 'Apakah engkau tidak memperhatikan bahwa Allah mengetahui apa yang ada di langit dan apa yang ada di bumi? Tidak ada pembicaraan rahasia antara tiga orang, kecuali Dialah yang keempatnya dan tidak ada lima orang, kecuali Dialah yang keenamnya. Tidak kurang dari itu atau lebih banyak, kecuali Dia bersama mereka di mana pun mereka berada. Kemudian, Dia memberitakan apa yang telah mereka kerjakan kepada mereka pada hari Kiamat. Sesungguhnya Allah Maha Mengetahui segala sesuatu. ', '', 'https://everyayah.com/data/Alafasy_128kbps/058007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('58:8', 58, 8, 28, 543, 5112, 'اَلَمْ تَرَ اِلَى الَّذِيْنَ نُهُوْا عَنِ النَّجْوٰى ثُمَّ يَعُوْدُوْنَ لِمَا نُهُوْا عَنْهُ وَيَتَنٰجَوْنَ بِالْاِثْمِ وَالْعُدْوَانِ وَمَعْصِيَتِ الرَّسُوْلِۖ وَاِذَا جَاۤءُوْكَ حَيَّوْكَ بِمَا لَمْ يُحَيِّكَ بِهِ اللّٰهُ ۙوَيَقُوْلُوْنَ فِيْٓ اَنْفُسِهِمْ لَوْلَا يُعَذِّبُنَا اللّٰهُ بِمَا نَقُوْلُۗ حَسْبُهُمْ جَهَنَّمُۚ يَصْلَوْنَهَاۚ فَبِئْسَ الْمَصِيْرُ ', 'Apakah engkau tidak memperhatikan orang-orang yang telah dilarang mengadakan pembicaraan rahasia, kemudian mereka kembali (melakukan) apa yang telah dilarang itu? Mereka saling mengadakan pembicaraan rahasia untuk berbuat dosa, permusuhan, dan durhaka kepada Rasul. Apabila datang kepadamu (Nabi Muhammad), mereka mengucapkan salam kepadamu dengan cara yang bukan sebagaimana yang ditentukan Allah untukmu. Mereka mengatakan dalam hati, “Mengapa Allah tidak menyiksa kita atas apa yang kita katakan?” Cukuplah bagi mereka (neraka) Jahanam yang akan mereka masuki. Maka, (neraka itu) seburuk-buruk tempat kembali. ', '', 'https://everyayah.com/data/Alafasy_128kbps/058008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('58:9', 58, 9, 28, 543, 5113, 'يٰٓاَيُّهَا الَّذِيْنَ اٰمَنُوْٓا اِذَا تَنَاجَيْتُمْ فَلَا تَتَنَاجَوْا بِالْاِثْمِ وَالْعُدْوَانِ وَمَعْصِيَتِ الرَّسُوْلِ وَتَنَاجَوْا بِالْبِرِّ وَالتَّقْوٰىۗ وَاتَّقُوا اللّٰهَ الَّذِيْٓ اِلَيْهِ تُحْشَرُوْنَ', 'Wahai orang-orang yang beriman, apabila kamu saling mengadakan pembicaraan rahasia, janganlah berbicara tentang perbuatan dosa, permusuhan, dan durhaka kepada Rasul. Akan tetapi, berbicaralah tentang perbuatan kebajikan dan takwa. Bertakwalah kepada Allah yang hanya kepada-Nya kamu akan dikumpulkan. ', '', 'https://everyayah.com/data/Alafasy_128kbps/058009.mp3');
PRAGMA foreign_keys = ON;
